// Lead Enrichment & Scoring Engine
const input = $input.first();
const apiResponse = input.json;
const places = apiResponse.results;
const minRating = parseFloat($('On form submission').first().json['Min Google Rating']) || 0;
const hotThreshold = parseInt($('On form submission').first().json['Hot Lead Score Threshold']) || 60;

const scoredLeads = [];
for (const place of places) {
  const name = place.name || 'Unknown';
  const address = place.formatted_address;
  const rating = place.rating || 0;
  const reviewCount = place.user_ratings_total || 0;
  const priceLevel = place.price_level || 0;
  const isOpen = place.opening_hours?.open_now;
  const types = place.types;
  const placeId = place.place_id;
  const phone = place.formatted_phone_number || 'NA';
  const website = place.website || 'NA';

  let score = 0;
  let scoreBreakdown = [];

  // 1. Google Rating (0-25 pts)
  const ratingScore = Math.round(rating / 5 * 25);
  score += ratingScore;
  scoreBreakdown.push(`Rating: ${ratingScore}pts (${rating})`);

  // 2. Review Volume (0-20 pts)
  let reviewScore = 0;
  if (reviewCount >= 500) reviewScore = 20;
  else if (reviewCount >= 200) reviewScore = 15;
  else if (reviewCount >= 100) reviewScore = 10;
  else if (reviewCount >= 50) reviewScore = 5;
  else if (reviewCount >= 20) reviewScore = 3;
  score += reviewScore;
  scoreBreakdown.push(`Reviews: ${reviewScore}pts (${reviewCount})`);

  // 3. No Website = Higher Need (0-20 pts)
  let websiteScore = 0;
  if (!website || website === 'NA') { websiteScore = 20; scoreBreakdown.push('No website: 20pts'); }
  else { websiteScore = 5; scoreBreakdown.push('Has website: 5pts'); }
  score += websiteScore;

  // 4. Currently Open (10 pts)
  if (isOpen === true) { score += 10; scoreBreakdown.push('Currently open: 10pts'); }

  // 5. Improvement Opportunity (10 pts)
  if (rating > 0 && rating < 4.0 && reviewCount >= 30) { score += 10; scoreBreakdown.push('Improvement opportunity: 10pts'); }

  // 6. Price Level (0-15 pts)
  if (priceLevel === 2 || priceLevel === 3) { score += 15; scoreBreakdown.push(`Price tier ${priceLevel}: 15pts`); }
  else if (priceLevel === 1) { score += 5; scoreBreakdown.push('Price tier 1: 5pts'); }

  if (minRating > 0 && rating < minRating) continue;

  const status = score >= hotThreshold ? 'HOT - Call Now' : 'NURTURE';
  const priority = score >= 80 ? 'HIGH' : score >= 60 ? 'MEDIUM' : 'LOW';

  scoredLeads.push({
    json: {
      name, address, phone, website,
      google_rating: rating, review_count: reviewCount, price_level: priceLevel, place_id: placeId,
      lead_score: score, lead_status: status, priority,
      score_breakdown: scoreBreakdown.join(', '),
      scored_at: new Date().toISOString(),
      hot_threshold_used: hotThreshold,
      google_maps_url: `https://maps.google.com/?cid=${placeId}`
    }
  });
}

scoredLeads.sort((a, b) => b.json.lead_score - a.json.lead_score);
return scoredLeads;
